"use strict";(self.webpackChunksite=self.webpackChunksite||[]).push([[6099],{9814:n=>{n.exports=JSON.parse('{"lang":"jv","resources":{"landing":{"meta":{"title":"Linguist \u2013 Ekstensi Terjemahan ingkang Ngutamakaken Privasi kangg\xe9 Chrome lan Firefox","description":"Ekstensi browser ingkang nerjemahaken kaca web, teks ingkang dipunpilih, lan subtitle. Saged mlampah kanthi cepet lan ndhukung terjemahan offline."},"navigation":{"features":{"content":"Fitur"},"blog":{"content":"Blog"},"docs":{"content":"Dokumen"},"github":{"content":"GitHub"}},"install":{"chrome":"Pasang kangg\xe9 Chrome","firefox":"Pasang kangg\xe9 Firefox"},"sections":{"hero":{"title":"Terjemahaken menapa kemawon ing browser panjenengan","description":"Linguist inggih menika ekstensi browser ingkang nerjemahaken teks kanthi cepet.\\n\\nTerjemahaken sedaya kaca web, teks ingkang dipunpilih, subtitle Netflix, lan pesen pribadi. Mirengaken teks ingkang dipunterjemahaken lan simpen terjemahan penting ing kamus pribadi panjenengan kangg\xe9 sinau tembung \xe9nggal, sanajan saweg offline.\\n\\nLinguist minangka alternatif modern ingkang ngutamakaken privasi kangg\xe9 ekstensi browser Google Translate. Cobi kanthi gratis."},"opensource":{"title":"Open source","content":"Linguist inggih menika ekstensi terjemahan browser ingkang gratis lan <0>open-source</0>. Ekstensi menika mboten ngempalaken utawi nyad\xe9 data pangguna.\\n\\nPanjenengan saged <1>donasi</1> kangg\xe9 ndhukung Linguist lan mbantu njagi kamardikan sarta kualitas ingkang sa\xe9.\\n\\nBag\xe9kaken Linguist ing media sosial supados tiyang san\xe8s saged manggihaken ekstensi menika."},"support":{"title":"Bantuan","content":"Menawi panjenengan gadhah pitak\xe8nan, hubungi kami <0/>.\\nMenawi panjenengan manggihaken bug lan gadhah akun GitHub, mangga <1>damel laporan (issue)</1>."},"createdBy":{"content":"Dipun damel d\xe9ning <0/>."}},"features":{"title":"Fitur","items":{"offlineTranslation":{"title":"Terjemahan offline lan privasi","content":"Terjemahaken teks langsung ing piranti panjenengan mawi penerjemah offline ingkang sampun cumawis. Teks panjenengan tetep aman lan mboten dipunkirim langkung internet.\\n\\nAktifaken fitur menika ing kaca pilihan supados terjemahan tetep rahasia nalika panjenengan maos email, dokumen, utawi pesen pribadi.\\n\\nPenerjemah offline ugi ngidini panjenengan nerjemahaken kaca web tanpa sambungan internet, ingkang migunani sanget nalika panjenengan saweg lelungan."},"fullPageTranslation":{"title":"Terjemahan kaca wutuh","content":"Terjemahan kaca wutuh ingkang cepet lan gadhah kualitas sa\xe9 namung mawi sawetawis klik.\\n\\nGinakaken tombol trabasan (hotkey) kangg\xe9 nerjemahaken kanthi cepet. Sorot teks ingkang dipunterjemahaken kangg\xe9 ningali teks aslinipun. Terjemahaken ugi kaca pribadi ingkang mbetahaken login utawi paywall.\\n\\nAtur paugeran terjemahan otomatis adhedhasar basa utawi domain kaca web.\\n\\nLinguist ngginakaken cara modifikasi kaca ingkang minimal: namung ng\xe9wahi bagean teks lan njagi tata letak kaca sarta kenyamanan pangguna.\\n\\nAktifaken terjemahan langsung (real-time) kangg\xe9 rapat mawi man\xe9ka basa ing Zoom, Google Meet, lan Microsoft Teams."},"selectedTextTranslation":{"title":"Terjemahan teks ingkang dipunpilih","content":"Manggihaken tembung ingkang mboten dipunmangertosi nalika maos artikel online?\\nCukup pilih teks ing kaca kasebut lan klik tombol terjemahaken.\\n\\nMirengaken teks asli lan terjemahanipun, sarta simpen terjemahan ing kamus panjenengan kangg\xe9 dipunsinaoni malih mangk\xe9."},"textTranslation":{"title":"Terjemahan teks cepet","content":"Mbetahaken terjemahan kanthi cepet? Klik ikon Linguist lan lebetaken teks panjenengan.\\n\\nMboten prelu pindhah tab utawi mbikak situs web terjemahan. Terjemahaken langsung ing browser panjenengan ngginakaken layanan ingkang panjenengan remeni."},"knowledgeBase":{"title":"Damel pusat pangetahuan pribadi panjenengan","content":"Saben terjemahan dipunsimpen ing riwayat panjenengan, lan panjenengan saged nambahaken cathetan penting ing kamus pribadi. Padosi kamus lan riwayat terjemahan panjenengan kapan kemawon.\\n\\nMboten wonten ingkang ical, sanajan nalika panjenengan saweg riset utawi sinau ing wekdal ingkang dangu.\\n\\nKamus menika saged mlampah kanthi offline, sa\xe9ngga Linguist cocog sanget kangg\xe9 tiyang ingkang saweg sinau basa lan tiyang ingkang asring lelungan ingkang mbetahaken akses terus-terusan dhateng daftar tembungipun."},"customTranslators":{"title":"Penerjemah kustom","content":"Linguist ngidini panjenengan milih layanan terjemahan pundi ingkang badh\xe9 dipunginakaken.\\n\\nEkstensi menika ndhukung panyedhiya terjemahan populer kados Google, Yandex, lan Microsoft, kanthi langkung saking 100 basa ingkang cumawis.\\n\\nMenawi layanan ingkang panjenengan betahaken mboten wonten, panjenengan saged nambahaken minangka <0>penerjemah kustom</0>.\\n\\nPenerjemah kustom ngidini panjenengan nggabungaken sistem terjemahan menapa kemawon \u2014 saking layanan LLM modern kados ChatGPT, DeepL, DeepSeek, lan Gemini dumugi penerjemah lokal ingkang mlampah ing piranti panjenengan, kados Ollama utawi LibreTranslate."}}},"faq":{"title":"FAQ","items":{"whatIsLinguist":{"title":"Menapa menika Linguist?","content":"Linguist inggih menika ekstensi terjemahan browser ingkang ngutamakaken privasi kangg\xe9 Chrome lan Firefox.\\n\\nEkstensi menika ngidini panjenengan nerjemahaken kaca web wutuh, teks ingkang dipunpilih, subtitle, lan pesen langsung ing browser panjenengan tanpa prelu pindhah dhateng situs web terjemahan san\xe8s."},"whyLinguist":{"title":"K\xe9nging menapa ngginakaken Linguist?","content":"Wonten kathah ekstensi browser ingkang nerjemahaken kaca web, lan sawetawis browser malah sampun gadhah penerjemah gawan. Lajeng k\xe9nging menapa kedah ngginakaken Linguist?\\n\\nKathah-kathahipun penerjemah gawan lan ekstensi terjemahan winates ing babagan fleksibilitas. Kathah ingkang namung gumantung ing satunggal panyedhiya terjemahan kados Google Translate utawi Microsoft Bing, sawetawis Firefox nawakaken penerjemah offline piyambak. Ing kathah kahanan, panjenengan mboten saged milih layanan ingkang paling cocog kaliyan kabetahan panjenengan.\\n\\nMenawi kualitas terjemahanipun mboten cekap sa\xe9 kangg\xe9 kabetahan panjenengan, utawi menawi ngirim teks pribadi dhateng layanan pihak katelu mboten saged dipuntampi, kathah piranti ingkang mboten maringi alternatif ingkang sa\xe9.\\n\\nKathah piranti ugi namung fokus ing satunggal tugas. Wonten ingkang nerjemahaken kaca wutuh, sawetawis san\xe8sipun namung nerjemahaken teks ingkang dipunpilih.\\n\\nIng wekdal ingkang sami, sawetawis ekstensi terjemahan dipundamel utaminipun kangg\xe9 pados bathi (monetisasi). Fitur kados riwayat terjemahan utawi kamus pribadi saged kemawon mbetahaken langganan, lan kadhangkala fitur dhasar kados tema peteng (dark theme) dipunanggep minangka pilihan premium.\\n\\nLinguist ngginakaken cara ingkang b\xe9da. Ekstensi menika dipunrancang minangka piranti terjemahan ingkang praktis. Panjenengan saged milih layanan terjemahan ingkang paling sa\xe9 kangg\xe9 panjenengan, gantos panyedhiya layanan, utawi nambahaken penerjemah kustom panjenengan piyambak.\\n\\nLinguist ugi ngempalaken sedayanipun ing satunggal panggenan: nerjemahaken kaca web wutuh, teks ingkang dipunpilih, subtitle, lan pesen sinambi nyathet terjemahan penting ing riwayat lan kamus pribadi panjenengan."},"theLinguistLogo":{"title":"K\xe9nging menapa logo Linguist menika Menara Babel?","content":"Logo Linguist kapundhut saking cariyos <wiki>Menara Babel</wiki>, salah satunggaling cariyos paling sepuh babagan basa lan komunikasi.\\n\\nMiturut cariyos kasebut, manungsa rumiyin ngginakaken basa ingkang sami lan nyobi mbangun menara ingkang nggayuh langit. Menara kasebut mboten nat\xe9 rampung, lan manungsa kasebar mawi man\xe9ka warna basa. Wiwit wekdal menika, b\xe9daning basa asring ndadosaken komunikasi langkung awrat.\\n\\nLinguist dipundamel kangg\xe9 mbantu ngrampungaken masalah menika.\\n\\nMenara Babel ing logo menika minangka pang\xe9ling-\xe9ling cariyos kasebut: kathah basa, kathah budaya, lan usaha manungsa ingkang terus-terusan kangg\xe9 mangertosi setunggal lan san\xe8sipun. Linguist mbantu nyambungaken pamb\xe9da kasebut kanthi ndadosaken terjemahan langkung gampil, fleksibel, lan saged dipunakses langsung ing browser panjenengan.\\n\\nLogo menika ugi nggambaraken semangat proyek menika. Linguist san\xe8s namung wadhah kangg\xe9 \\"Google Translate\\". Ekstensi menika dipundamel d\xe9ning tiyang-tiyang ingkang peduli dhateng basa, privasi, lan teknologi terbuka. Menara Babel nglambangaken rasa p\xe9ngin mangertos, pasinaon, lan pamanggih bilih b\xe9daning basa kedahipun nyawijikaken manungsa, san\xe8s misahaken."},"imageTranslation":{"title":"K\xe9nging menapa Linguist mboten nerjemahaken teks ing gambar?","content":"Linguist fokus ing fitur terjemahan ingkang saged dipunandelaken lan gadhah kualitas sa\xe9.\\n\\nKami sampun nliti man\xe9ka cara kangg\xe9 nerjemahaken teks ing salebeting gambar. Wekdal menika, kathah-kathahipun solusi ingkang wonten mboten maringi asil ingkang konsisten, utaminipun nalika dipunlampahaken langsung ing browser \u2014 ingkang wigati sanget kangg\xe9 njagi privasi pangguna.\\n\\nAmargi menika, Linguist wekdal menika mboten nyertakaken terjemahan gambar. Kami langkung milih mboten ngedalaken fitur ingkang mboten jumbuh kaliyan standar kualitas kami.\\n\\nMenawi kami manggihaken cara ingkang saged dipunandelaken lan ngurmati privasi kangg\xe9 ngetrapaken terjemahan gambar ing temb\xe9 wingking, kami badh\xe9 kanthi bingah nambahaken fitur kasebut."},"howTranslatePages":{"title":"Kados pundi Linguist nerjemahaken kaca web?","content":"Linguist saged nerjemahaken kaca web wutuh namung mawi sawetawis klik. Panjenengan saged miwiti terjemahan kaca ngginakaken tombol ekstensi utawi trabasan keyboard (shortcut).\\n\\nTeks asli badh\xe9 tetep saged dipunakses. Sorot teks ingkang dipunterjemahaken kangg\xe9 ningali teks aslinipun."},"offlineTranslation":{"title":"Menapa Linguist saged nerjemahaken kaca kanthi offline?","content":"Inggih. Linguist nyertakaken penerjemah offline gawan ingkang ngidini panjenengan nerjemahaken teks tanpa ngirim data langkung internet.\\n\\nMenika mbantu njagi privasi panjenengan lan ngidini panjenengan nerjemahaken konten sanajan tanpa sambungan internet."},"privacy":{"title":"Menapa Linguist njagi privasi?","content":"Inggih. Linguist dipunrancang kanthi ngutamakaken privasi.\\n\\nEkstensi menika mboten ngempalaken utawi nyad\xe9 data pangguna. Nalika ngginakaken <offline-translator>penerjemah offline</offline-translator>, terjemahan dipunproses sagemblengipun ing piranti panjenengan."},"supportedBrowsers":{"title":"Browser menapa kemawon ingkang dipundhukung d\xe9ning Linguist?","content":"Linguist cumawis kangg\xe9 Chrome lan Firefox. Ekstensi menika ugi saged mlampah ing browser adhedhasar Chromium san\xe8sipun ingkang ndhukung ekstensi Chrome.\\n\\nLinguist ugi saged mlampah ing browser Android ingkang ndhukung ekstensi, kados Firefox kangg\xe9 Android lan sawetawis browser adhedhasar Chromium."},"selectedText":{"title":"Menapa Linguist saged nerjemahaken teks ingkang dipunpilih?","content":"Inggih. Cukup pilih teks ing kaca web menapa kemawon lan ginakaken tombol terjemahaken kangg\xe9 nerjemahaken kanthi cepet.\\n\\nPanjenengan ugi saged mirengaken terjemahanipun lan nyimpen ing kamus pribadi panjenengan."},"customTranslators":{"title":"Menapa kula saged ngginakaken layanan terjemahan kula piyambak?","content":"Inggih. Linguist ndhukung <custom-translator>penerjemah kustom</custom-translator>, ingkang ngidini panjenengan nggabungaken layanan terjemahan tambahan.\\n\\nPanjenengan saged nyambungaken API eksternal utawi sistem terjemahan lokal kados <libre-translate>LibreTranslate</libre-translate> utawi <ollama>Ollama</ollama>."},"isFree":{"title":"Menapa Linguist menika gratis?","content":"Inggih. Linguist menika gratis sagemblengipun lan <linguist>open source</linguist>.\\n\\nProyek menika dipundhukung d\xe9ning komunitas, lan panjenengan saged milih kangg\xe9 <donations>ndhukung mawi donasi</donations>."}}}}},"altVersions":[{"langCode":"ar","langName":"\u0627\u0644\u0639\u0631\u0628\u064a\u0629","url":"https://linguister.io/ar"},{"langCode":"bn","langName":"\u09ac\u09be\u0982\u09b2\u09be","url":"https://linguister.io/bn"},{"langCode":"de","langName":"Deutsch","url":"https://linguister.io/de"},{"langCode":"en","langName":"English","url":"https://linguister.io/"},{"langCode":"es","langName":"espa\xf1ol","url":"https://linguister.io/es"},{"langCode":"fr","langName":"fran\xe7ais","url":"https://linguister.io/fr"},{"langCode":"gu","langName":"\u0a97\u0ac1\u0a9c\u0ab0\u0abe\u0aa4\u0ac0","url":"https://linguister.io/gu"},{"langCode":"hi","langName":"\u0939\u093f\u0928\u094d\u0926\u0940","url":"https://linguister.io/hi"},{"langCode":"it","langName":"italiano","url":"https://linguister.io/it"},{"langCode":"ja","langName":"\u65e5\u672c\u8a9e","url":"https://linguister.io/ja"},{"langCode":"jv","langName":"Jawa","url":"https://linguister.io/jv"},{"langCode":"ko","langName":"\ud55c\uad6d\uc5b4","url":"https://linguister.io/ko"},{"langCode":"mr","langName":"\u092e\u0930\u093e\u0920\u0940","url":"https://linguister.io/mr"},{"langCode":"pa","langName":"\u0a2a\u0a70\u0a1c\u0a3e\u0a2c\u0a40","url":"https://linguister.io/pa"},{"langCode":"pt","langName":"portugu\xeas","url":"https://linguister.io/pt"},{"langCode":"ru","langName":"\u0440\u0443\u0441\u0441\u043a\u0438\u0439","url":"https://linguister.io/ru"},{"langCode":"ta","langName":"\u0ba4\u0bae\u0bbf\u0bb4\u0bcd","url":"https://linguister.io/ta"},{"langCode":"tr","langName":"T\xfcrk\xe7e","url":"https://linguister.io/tr"},{"langCode":"ur","langName":"\u0627\u0631\u062f\u0648","url":"https://linguister.io/ur"},{"langCode":"vi","langName":"Ti\u1ebfng Vi\u1ec7t","url":"https://linguister.io/vi"},{"langCode":"zh","langName":"\u4e2d\u6587","url":"https://linguister.io/zh"}]}')}}]);